// Auto-generated icon assets
export const ICO_SWORD = "data:image/png;base64,";
export const ICO_TROPHY = "data:image/png;base64,";
export const ICO_BOOK = "data:image/png;base64,";
export const ICO_SOUND = "data:image/png;base64,";
export const ICO_MUTE = "data:image/png;base64,";
export const ICO_GEM = "data:image/png;base64,";
export const ICO_MAP = "data:image/png;base64,";
export const ICO_CHURCH = "data:image/png;base64,";
export const ICO_SKULL = "data:image/png;base64,";
export const ICO_FIRE = "data:image/png;base64,";
export const ICO_STAR = "data:image/png;base64,";
export const ICO_EXPLOSION = "data:image/png;base64,";
export const ICO_SPROUT = "data:image/png;base64,";
export const ICO_CHART = "data:image/svg+xml;base64,";

export const ICONS = {
  sword: ICO_SWORD, trophy: ICO_TROPHY, book: ICO_BOOK,
  sound: ICO_SOUND, mute: ICO_MUTE, gem: ICO_GEM,
  map: ICO_MAP, church: ICO_CHURCH, skull: ICO_SKULL,
  fire: ICO_FIRE, star: ICO_STAR, explosion: ICO_EXPLOSION,
  sprout: ICO_SPROUT, chart: ICO_CHART
};

export function ico(name, cls = '') {
  const src = ICONS[name];
  if (!src) return '';
  return `<img src="${src}" class="game-icon${cls ? ' ' + cls : ''}" alt="${name}">`;
}
